import{_ as e,o as p,c as a,ai as o}from"./chunks/framework.CzqNhXfh.js";const u=JSON.parse('{"title":"写在致谢之前","description":"","frontmatter":{},"headers":[],"relativePath":"essays/content.md","filePath":"essays/content.md","lastUpdated":1776823395000}'),s={name:"essays/content.md"};function n(r,t,c,_,d,i){return p(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="写在致谢之前" tabindex="-1">写在致谢之前 <a class="header-anchor" href="#写在致谢之前" aria-label="Permalink to &quot;写在致谢之前&quot;">​</a></h1><blockquote><p>原创 子昂 闲谈之余 2025年4月12日 19:59 湖北</p></blockquote><p>毕业论文完结，走向了最后的章节：致谢</p><p>以往，有无数次对致谢的构想，翻来覆去的情绪和精心编制的话语，滔滔不绝。直至此刻，将要落笔之时，却不知从何处写起。所以有了这篇写在致谢之前。</p><p>致谢，从启笔那刻起，就开启了对本科四年时光的追忆。开始追寻，刚迈入校园时我的模样，是无知、干涩、胆怯，也是踏实、天真、幸运。原来仅仅四年就可以抹去一个人的特质，又添上一些。像一场未知的化学反应，有得有失，焕然一新。&quot;我有变得更好吗？&quot;这个问题，快要毕业的我可以回答了。你很幸运，心里有一个理想的自己，一直努力地朝着它奔去。</p><p>再让我想想，有哪些忘不掉的时刻。</p><p>第一次吃韵酒，初尝了大学的味道，那是骄阳和拥挤的人来人往。加入了学创大家庭，结识了很多学长学姐和同学，温暖、关怀、团结，一起举办活动，一起开会，一起欢声笑语，其中很多人直至现在都关系很好，大学四年从他们身上受益良多。东九灭灯以后，我走过泛着橘色灯光的玉兰花群，独径小路充满着清香，搭配着内心安宁永远是美味佳肴。</p><p>参加了很多比赛，无论获奖与否，和队友们并肩作战的感觉让我兴奋，也使我安心，我记得很多个日夜兼程，期待，疲惫，紧张，坦然，喜悦，失落。脑海中的他们和她们一张张闪过。这才是比赛最大的意义所在吧。小组作业展示或答辩，从结巴卡顿的无措，到勇于登台的自如，向观众展示原来并不是一件感到害怕的事情，我越来越享受了。上午的课，下午的会，晚上的考试，永远难以清空的待办事项，忙碌贯穿，日复一日。</p><p>大学的第一次恋爱，开始匆匆，结束匆匆，遗憾的只是结果导向，而现在的我更关注来时的过程，始终是一场不后悔的体验。忙碌的夏天，不充足的准备，一场接一场的笔面试，跌宕起伏的心情每日升降的太阳遥相呼应，认识了天南地北的朋友们，虽短暂相遇，却令人怀念共同奔赴的三两天。刚刚通关黑神话第四章的我，正准备前往下一关时，接到了来自清深老师的录取电话，秋桂飘香，安稳的喜悦更压一头，那是好久不见的我。</p><p>写着写着，绵长的回忆总结成了寥寥几句，小小的可惜，记忆定格的渴望感无比浓烈。寻找了这么久，你要感谢谁呢？来一个正式真诚的致谢版本吧。（你是否想起了大学升学宴的致辞呢？）</p><p>首先，要感谢我的父母。四年本科生活，需要不少费用，这对我的家庭并不容易。虽然他们并没有参与我的大学生活，平常也听不懂我讲的东西，但我知道他们始终挂念着，愿意给我最好的，这就够了。无父母之养，无以至今日。</p><p>其次，要感谢我的老师。杨珺老师在毕业设计上提供了很多关键建议和指导，每次都能认真的读完我的回稿并且给出详细修改意见，不苟言笑的严厉感扑面而来。她身上有股严苛的认真劲，不知不觉感染到我，让我愿意花时间去打磨。大学四年中，每一门授课老师都值得感谢，也许教学内容不同，风格迥异。但我的所学所识，离不开每一位老师的用心倾注。</p><p>再而，感谢我遇到的同学和朋友。给予我帮助指导的，给予我反思学习的，给予我伤痛成长的，给予我快乐陪伴的，能遇见这样一群人，颇感幸运。个人的成长永远离不开环境的影响，环境就是和不同的人相处，一起经历喜怒哀乐，逐渐蜕变。纵看人生长河，大学四年结识的朋友们，以后到了天南地北，还能相视一笑，该多好。感谢相遇！</p><p>最后，感谢自己。在无数个无人的夜里，你掉入了深坑中，捂住了伤口，忍受着疼痛，一次又一次地爬了起来。因为你从来不会在抵达长跑终点前喊暂停，永远相信天光见明，雨落花开。谢谢你走到了今天，祝愿你能坚定着走下去！</p>',14)])])}const m=e(s,[["render",n]]);export{u as __pageData,m as default};
